test.describe('Conversion Funnel Widget', () => {
  test('should load conversion funnel widget page', async ({ page }) => {
    const response = await page.goto('/admin/widgets/conversion-funnel.html', {
      waitUntil: 'load',
      timeout: 15000
    });

    expect(response?.status()).toBe(200);

    const title = await page.title();
    expect(title).toContain('Conversion Funnel');
  });

  test('should render funnel widget container', async ({ page }) => {
    await page.goto('/admin/widgets/conversion-funnel.html', {
      waitUntil: 'domcontentloaded'
    });

    await page.waitForTimeout(500);

    const funnelWidget = page.locator('.conversion-funnel-widget');
    await expect(funnelWidget).toBeVisible();
  });

  test('should have funnel header and title', async ({ page }) => {
    await page.goto('/admin/widgets/conversion-funnel.html', {
      waitUntil: 'domcontentloaded'
    });

    const header = page.locator('.funnel-header');
    await expect(header).toBeVisible();

    const title = page.locator('.funnel-title');
    await expect(title).toBeVisible();
  });

  test('should have funnel stages', async ({ page }) => {
    await page.goto('/admin/widgets/conversion-funnel.html', {
      waitUntil: 'domcontentloaded'
    });

    const stagesContainer = page.locator('.funnel-stages');
    await expect(stagesContainer).toBeVisible();
  });

  test('should be responsive on mobile', async ({ page }) => {
    await page.setViewportSize({ width: 375, height: 667 });
    await page.goto('/admin/widgets/conversion-funnel.html', {
      waitUntil: 'domcontentloaded'
    });

    const funnelWidget = page.locator('.conversion-funnel-widget');
    await expect(funnelWidget).toBeVisible();
  });
});

