test.describe('All Widgets - Integration Tests', () => {
  test('should load all widgets on dashboard', async ({ page }) => {
    const response = await page.goto('/admin/dashboard.html', {
      waitUntil: 'load',
      timeout: 20000
    });

    expect(response?.status()).toBe(200);

    await page.waitForTimeout(2000);

    const kpiCards = page.locator('kpi-card-widget, [class*="kpi-card"]');
    await expect(kpiCards).toHaveCount({ gte: 1 });
  });

  test('should have no console errors when loading widgets', async ({ page }) => {
    const errors: string[] = [];

    page.on('console', (msg) => {
      if (msg.type() === 'error') {
        const text = msg.text();
        if (text.includes('supabase')) return;
        if (text.includes('__ENV__')) return;
        if (text.includes('CustomElementRegistry')) return;
        errors.push(text);
      }
    });

    await page.goto('/admin/widgets-demo.html', {
      waitUntil: 'load',
      timeout: 20000
    });

    await page.waitForTimeout(1000);

    expect(errors.length, `Console errors: ${errors.join(', ')}`).toBe(0);
  });
});
